import{_ as e,o as l,c as a,a2 as r}from"./chunks/framework.Pywvta2k.js";const f=JSON.parse('{"title":"药食同源方精选","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/07-食疗养生/03-药食同源方精选.md","filePath":"tcm-data/07-食疗养生/03-药食同源方精选.md","lastUpdated":1781084559000}'),d={name:"tcm-data/07-食疗养生/03-药食同源方精选.md"};function n(s,t,g,o,i,x){return l(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="药食同源方精选" tabindex="-1">药食同源方精选 <a class="header-anchor" href="#药食同源方精选" aria-label="Permalink to &quot;药食同源方精选&quot;">​</a></h1><blockquote><p>既是食物，也是药物——不同体质的药膳选择</p></blockquote><hr><h2 id="一、患者-男-专用-温阳祛湿" tabindex="-1">一、患者（男）专用（温阳祛湿） <a class="header-anchor" href="#一、患者-男-专用-温阳祛湿" aria-label="Permalink to &quot;一、患者（男）专用（温阳祛湿）&quot;">​</a></h2><h3 id="_1-当归生姜羊肉汤-医圣张仲景方" tabindex="-1">1. 当归生姜羊肉汤（医圣张仲景方） <a class="header-anchor" href="#_1-当归生姜羊肉汤-医圣张仲景方" aria-label="Permalink to &quot;1. 当归生姜羊肉汤（医圣张仲景方）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>出自</strong></td><td style="text-align:left;">《金匮要略》——&quot;寒疝腹中痛，及胁痛里急者&quot;</td></tr><tr><td style="text-align:left;"><strong>材料</strong></td><td style="text-align:left;">羊肉500g + 当归20g + 生姜30g + 盐少许</td></tr><tr><td style="text-align:left;"><strong>做法</strong></td><td style="text-align:left;">羊肉焯水后与当归、生姜同炖2小时</td></tr><tr><td style="text-align:left;"><strong>功效</strong></td><td style="text-align:left;"><strong>温中补虚、祛寒止痛</strong>——最适合阳虚寒湿体质</td></tr><tr><td style="text-align:left;"><strong>患者（男）</strong></td><td style="text-align:left;">⭐ <strong>冬季每周1次</strong>——温肾阳、通血脉</td></tr></tbody></table><h3 id="_2-理中培土粥-版·温阳型" tabindex="-1">2. 理中培土粥（版·温阳型） <a class="header-anchor" href="#_2-理中培土粥-版·温阳型" aria-label="Permalink to &quot;2. 理中培土粥（版·温阳型）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>材料</strong></td><td style="text-align:left;">炒薏米30g + 茯苓15g + 山药20g + 芡实15g + 生姜5片 + 大枣5枚 + 小米适量</td></tr><tr><td style="text-align:left;"><strong>功效</strong></td><td style="text-align:left;"><strong>健脾祛湿、温中散寒</strong></td></tr><tr><td style="text-align:left;"><strong>频次</strong></td><td style="text-align:left;">每日早餐</td></tr><tr><td style="text-align:left;"><strong>对应</strong></td><td style="text-align:left;">面色暗沉（坤土湿）、腰凉（中焦寒）</td></tr></tbody></table><h3 id="_3-肉桂红糖饮" tabindex="-1">3. 肉桂红糖饮 <a class="header-anchor" href="#_3-肉桂红糖饮" aria-label="Permalink to &quot;3. 肉桂红糖饮&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>材料</strong></td><td style="text-align:left;">肉桂3g + 红糖1勺 + 生姜3片</td></tr><tr><td style="text-align:left;"><strong>做法</strong></td><td style="text-align:left;">沸水冲泡5分钟</td></tr><tr><td style="text-align:left;"><strong>功效</strong></td><td style="text-align:left;"><strong>引火归原、温中散寒</strong></td></tr><tr><td style="text-align:left;"><strong>频次</strong></td><td style="text-align:left;">下午酉时（17-19点）饮用——<strong>引火归原最佳时间</strong></td></tr></tbody></table><h3 id="_4-黑豆核桃汤" tabindex="-1">4. 黑豆核桃汤 <a class="header-anchor" href="#_4-黑豆核桃汤" aria-label="Permalink to &quot;4. 黑豆核桃汤&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>材料</strong></td><td style="text-align:left;">黑豆50g + 核桃仁30g + 大枣5枚</td></tr><tr><td style="text-align:left;"><strong>做法</strong></td><td style="text-align:left;">黑豆提前浸泡，与核桃、大枣同煮1小时</td></tr><tr><td style="text-align:left;"><strong>功效</strong></td><td style="text-align:left;"><strong>补肾乌发</strong>——针对头发花白</td></tr></tbody></table><hr><h2 id="二、患者-女-专用-培中养血" tabindex="-1">二、患者（女）专用（培中养血） <a class="header-anchor" href="#二、患者-女-专用-培中养血" aria-label="Permalink to &quot;二、患者（女）专用（培中养血）&quot;">​</a></h2><h3 id="_1-山药小米红枣粥" tabindex="-1">1. 山药小米红枣粥 <a class="header-anchor" href="#_1-山药小米红枣粥" aria-label="Permalink to &quot;1. 山药小米红枣粥&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>材料</strong></td><td style="text-align:left;">山药30g + 小米50g + 红枣5枚（掰开）+ 红糖少许</td></tr><tr><td style="text-align:left;"><strong>功效</strong></td><td style="text-align:left;"><strong>培补中气、养血安神</strong></td></tr><tr><td style="text-align:left;"><strong>频次</strong></td><td style="text-align:left;"><strong>每日早餐</strong>——非吃不可</td></tr><tr><td style="text-align:left;"><strong>对应</strong></td><td style="text-align:left;">晨起疲惫（中气虚）、面色不华（血虚）</td></tr></tbody></table><h3 id="_2-桂圆枸杞茶" tabindex="-1">2. 桂圆枸杞茶 <a class="header-anchor" href="#_2-桂圆枸杞茶" aria-label="Permalink to &quot;2. 桂圆枸杞茶&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>材料</strong></td><td style="text-align:left;">桂圆肉5枚 + 枸杞10g + 红枣2枚</td></tr><tr><td style="text-align:left;"><strong>做法</strong></td><td style="text-align:left;">沸水冲泡或煮5分钟</td></tr><tr><td style="text-align:left;"><strong>功效</strong></td><td style="text-align:left;"><strong>养血安神、益精明目</strong></td></tr><tr><td style="text-align:left;"><strong>频次</strong></td><td style="text-align:left;">每日上午或下午一杯</td></tr><tr><td style="text-align:left;"><strong>注意</strong></td><td style="text-align:left;">如有上火（口干加重），减桂圆至3枚</td></tr></tbody></table><h3 id="_3-乌梅三豆饮-彭子益方" tabindex="-1">3. 乌梅三豆饮（彭子益方） <a class="header-anchor" href="#_3-乌梅三豆饮-彭子益方" aria-label="Permalink to &quot;3. 乌梅三豆饮（彭子益方）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>出自</strong></td><td style="text-align:left;">《圆运动的古中医学》</td></tr><tr><td style="text-align:left;"><strong>材料</strong></td><td style="text-align:left;">乌梅5枚 + 黄豆30g + 黑豆30g + 绿豆30g + 冰糖少许</td></tr><tr><td style="text-align:left;"><strong>做法</strong></td><td style="text-align:left;">豆类浸泡后与乌梅同煮1小时，取汤饮用</td></tr><tr><td style="text-align:left;"><strong>功效</strong></td><td style="text-align:left;"><strong>养木平肝、清虚热</strong></td></tr><tr><td style="text-align:left;"><strong>频次</strong></td><td style="text-align:left;">烦躁潮热时连饮3-5天</td></tr><tr><td style="text-align:left;"><strong>对应</strong></td><td style="text-align:left;">烦躁、潮热、口干（虚火上炎）</td></tr></tbody></table><h3 id="_4-莲子百合银耳羹" tabindex="-1">4. 莲子百合银耳羹 <a class="header-anchor" href="#_4-莲子百合银耳羹" aria-label="Permalink to &quot;4. 莲子百合银耳羹&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>材料</strong></td><td style="text-align:left;">莲子20g + 百合15g + 银耳10g + 冰糖少许</td></tr><tr><td style="text-align:left;"><strong>功效</strong></td><td style="text-align:left;"><strong>养心安神、润肺生津</strong></td></tr><tr><td style="text-align:left;"><strong>频次</strong></td><td style="text-align:left;">每周3次，晚餐或睡前</td></tr><tr><td style="text-align:left;"><strong>对应</strong></td><td style="text-align:left;">失眠、口干、皮肤干</td></tr></tbody></table><h3 id="_5-红小豆薏米粥" tabindex="-1">5. 红小豆薏米粥 <a class="header-anchor" href="#_5-红小豆薏米粥" aria-label="Permalink to &quot;5. 红小豆薏米粥&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>材料</strong></td><td style="text-align:left;">红小豆30g + 炒薏米30g + 茯苓15g</td></tr><tr><td style="text-align:left;"><strong>功效</strong></td><td style="text-align:left;"><strong>健脾祛湿止带</strong></td></tr><tr><td style="text-align:left;"><strong>频次</strong></td><td style="text-align:left;">白带多时连食1周</td></tr><tr><td style="text-align:left;"><strong>注意</strong></td><td style="text-align:left;">薏米性寒，必须<strong>炒</strong>后用</td></tr></tbody></table><hr><h2 id="三、两人同用-共同适合" tabindex="-1">三、两人同用（共同适合） <a class="header-anchor" href="#三、两人同用-共同适合" aria-label="Permalink to &quot;三、两人同用（共同适合）&quot;">​</a></h2><h3 id="_1-姜枣茶-最佳晨起饮品" tabindex="-1">1. 姜枣茶（最佳晨起饮品） <a class="header-anchor" href="#_1-姜枣茶-最佳晨起饮品" aria-label="Permalink to &quot;1. 姜枣茶（最佳晨起饮品）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>材料</strong></td><td style="text-align:left;">生姜3片 + 红枣3枚（掰开）</td></tr><tr><td style="text-align:left;"><strong>做法</strong></td><td style="text-align:left;">煮水5分钟或沸水冲泡</td></tr><tr><td style="text-align:left;"><strong>功效</strong></td><td style="text-align:left;"><strong>温中散寒、升发阳气</strong></td></tr><tr><td style="text-align:left;"><strong>频次</strong></td><td style="text-align:left;">每日晨起</td></tr><tr><td style="text-align:left;"><strong>患者（男）加味</strong></td><td style="text-align:left;">可加<strong>肉桂1g</strong>（引火归原）</td></tr><tr><td style="text-align:left;"><strong>患者（女）减量</strong></td><td style="text-align:left;">如感上火，减生姜至1片</td></tr></tbody></table><h3 id="_2-艾叶生姜泡脚方" tabindex="-1">2. 艾叶生姜泡脚方 <a class="header-anchor" href="#_2-艾叶生姜泡脚方" aria-label="Permalink to &quot;2. 艾叶生姜泡脚方&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>材料</strong></td><td style="text-align:left;">艾叶30g + 生姜5大片</td></tr><tr><td style="text-align:left;"><strong>做法</strong></td><td style="text-align:left;">煮水15分钟，兑温水至40-45℃，泡15-20分钟至微汗</td></tr><tr><td style="text-align:left;"><strong>功效</strong></td><td style="text-align:left;"><strong>温通经络、引火归原、助眠</strong></td></tr><tr><td style="text-align:left;"><strong>频次</strong></td><td style="text-align:left;"><strong>每晚睡前</strong></td></tr><tr><td style="text-align:left;"><strong>患者（男）</strong></td><td style="text-align:left;">助腰腹温暖（艾叶）</td></tr><tr><td style="text-align:left;"><strong>患者（女）</strong></td><td style="text-align:left;">助引火归原、改善睡眠</td></tr><tr><td style="text-align:left;"><strong>注意</strong></td><td style="text-align:left;">❌ 不可大汗（微汗即止）</td></tr></tbody></table><h3 id="_3-红糖姜水" tabindex="-1">3. 红糖姜水 <a class="header-anchor" href="#_3-红糖姜水" aria-label="Permalink to &quot;3. 红糖姜水&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>频次</strong></td><td style="text-align:left;">雨天、受寒、疲劳时饮用</td></tr></tbody></table><hr><h2 id="四、忌口总表" tabindex="-1">四、忌口总表 <a class="header-anchor" href="#四、忌口总表" aria-label="Permalink to &quot;四、忌口总表&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">类别</th><th style="text-align:left;">忌什么</th><th style="text-align:left;">为什么</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>冰饮</strong></td><td style="text-align:left;">冰淇淋、冰水、冰咖啡</td><td style="text-align:left;">伤脾阳（两人都禁）</td></tr><tr><td style="text-align:left;"><strong>生冷水果</strong></td><td style="text-align:left;">大量西瓜、火龙果、柿子</td><td style="text-align:left;">寒湿伤阳</td></tr><tr><td style="text-align:left;"><strong>凉拌菜</strong></td><td style="text-align:left;">生菜沙拉（尤其冬天）</td><td style="text-align:left;">脾虚者难消化</td></tr><tr><td style="text-align:left;"><strong>绿豆</strong></td><td style="text-align:left;">绿豆汤（夏天少量可以）</td><td style="text-align:left;">性寒，伤阳</td></tr><tr><td style="text-align:left;"><strong>海鲜</strong></td><td style="text-align:left;">螃蟹、生蚝（尤其配冰啤）</td><td style="text-align:left;">寒性+湿气</td></tr><tr><td style="text-align:left;"><strong>油腻</strong></td><td style="text-align:left;">炸鸡、烧烤、肥肉</td><td style="text-align:left;">助湿生痰</td></tr><tr><td style="text-align:left;"><strong>浓茶</strong></td><td style="text-align:left;">浓普洱、浓绿茶</td><td style="text-align:left;">伤胃气；淡茶可饮</td></tr><tr><td style="text-align:left;"><strong>牛奶</strong></td><td style="text-align:left;">大量冰牛奶</td><td style="text-align:left;">生湿（患者（女）可喝温奶）</td></tr></tbody></table><hr><h2 id="五、四季食养总原则" tabindex="-1">五、四季食养总原则 <a class="header-anchor" href="#五、四季食养总原则" aria-label="Permalink to &quot;五、四季食养总原则&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">季节</th><th style="text-align:left;">患者（男）</th><th style="text-align:left;">患者（女）</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>春</strong></td><td style="text-align:left;">助升发：韭菜、芽菜、葱</td><td style="text-align:left;">养肝血：枸杞、菠菜</td></tr><tr><td style="text-align:left;"><strong>夏</strong></td><td style="text-align:left;">潜阳为主：少辛、多清淡</td><td style="text-align:left;">清虚热：乌梅三豆饮</td></tr><tr><td style="text-align:left;"><strong>秋</strong></td><td style="text-align:left;">润肺：梨水、银耳</td><td style="text-align:left;">滋阴：百合、银耳</td></tr><tr><td style="text-align:left;"><strong>冬</strong></td><td style="text-align:left;">⭐ 温补：羊肉汤、肉桂</td><td style="text-align:left;">温养：红枣桂圆、当归蛋</td></tr></tbody></table><hr><p><em>本条目为精简框架版。可扩展至&quot;药食同源100方&quot;&quot;常见食物性味归经表&quot;等专题。</em></p>',40)])])}const h=e(d,[["render",n]]);export{f as __pageData,h as default};
